import jwt
import datetime
import hashlib
import secrets

SECRET_KEY = 'your-secret-key'
ALGORITHM = 'HS256'

def generate_jwt(user_id, role):
    payload = {
        'iat': datetime.datetime.utcnow(),
        'exp': datetime.datetime.utcnow() + datetime.timedelta(minutes=30),
        'sub': user_id,
        'role': role
    }

    hashed_secret = hashlib.sha256(SECRET_KEY.encode()).digest()
    encoded_payload = jwt.encode(payload, hashed_secret, algorithm=ALGORITHM)

    return encoded_payload.decode('utf-8')